namespace sv_1afb3bbe08134c74bbd9795a60098259.Models;

public class PersonalInfoModel
{
    public string Name { get; set; } = "";
    public string Email { get; set; } = "";
}

public class JobHistoryEntry
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public string Duration { get; set; } = "";
}

public class ReferenceContact
{
    public string Name { get; set; } = "";
    public string Email { get; set; } = "";
    public string Relationship { get; set; } = "";
}

public class WizardProgress
{
    public HashSet<int> CompletedSteps { get; init; } = [];

    public static readonly (int Step, string Title, string Url)[] Steps =
    [
        (1, "Personal Info", "/apply/personal-info"),
        (2, "Experience", "/apply/experience"),
        (3, "References", "/apply/references"),
        (4, "Review", "/apply/review"),
    ];

    public static int? GetStepFromUrl(string url)
    {
        var path = new Uri(url).AbsolutePath;
        foreach (var (step, _, stepUrl) in Steps)
        {
            if (path.Equals(stepUrl, StringComparison.OrdinalIgnoreCase))
                return step;
        }
        return null;
    }
}

using sv_1afb3bbe08134c74bbd9795a60098259.Models;

namespace sv_1afb3bbe08134c74bbd9795a60098259.Services;

/// <summary>
/// Scoped (circuit-scoped) service that holds wizard form data.
/// Persists across enhanced navigations within the same circuit,
/// keeping each user's application data isolated.
/// </summary>
public class ApplicationState
{
    public PersonalInfoModel PersonalInfo { get; set; } = new();
    public List<JobHistoryEntry> Experience { get; set; } = [new()];
    public List<ReferenceContact> References { get; set; } = [new()];
}

@inherits LayoutComponentBase
@inject NavigationManager Nav

<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        <div class="top-row px-4">
            <div class="wizard-progress">
                @{
                    var currentStep = WizardProgress.GetStepFromUrl(Nav.Uri);
                }
                @foreach (var (step, title, url) in WizardProgress.Steps)
                {
                    var isActive = step == currentStep;
                    var isCompleted = Progress?.CompletedSteps.Contains(step) == true;

                    <a href="@url"
                       class="wizard-step @(isActive ? "active" : "") @(isCompleted ? "completed" : "")">
                        <span class="step-number">
                            @if (isCompleted && !isActive)
                            {
                                <span>&#10003;</span>
                            }
                            else
                            {
                                @step
                            }
                        </span>
                        <span class="step-title">@title</span>
                    </a>

                    @if (step < WizardProgress.Steps.Length)
                    {
                        <span class="step-connector @(isCompleted ? "completed" : "")"></span>
                    }
                }
            </div>
        </div>

        <article class="content px-4">
            @Body
        </article>
    </main>
</div>

<div id="blazor-error-ui" data-nosnippet>
    An unhandled error has occurred.
    <a href="." class="reload">Reload</a>
    <span class="dismiss">🗙</span>
</div>

