arguments.file_text:
@page "/apply/personal-info"
@layout ApplyLayout
@rendermode InteractiveServer

@using sv_1afb3bbe08134c74bbd9795a60098259.Models
@using sv_1afb3bbe08134c74bbd9795a60098259.Services

@inject ApplicationState AppState
@inject CascadingValueSource<WizardProgress> ProgressSource
@inject NavigationManager Nav

<PageTitle>Apply – Personal Info</PageTitle>

<h1>Step 1: Personal Information</h1>

<div class="mb-3" style="max-width: 500px;">
    <label class="form-label">Full Name</label>
    <input class="form-control" @bind="AppState.PersonalInfo.Name" />
</div>

<div class="mb-3" style="max-width: 500px;">
    <label class="form-label">Email Address</label>
    <input type="email" class="form-control" @bind="AppState.PersonalInfo.Email" />
</div>

<div class="d-flex gap-2 mt-4">
    <button class="btn btn-primary" @onclick="Next">Next &rarr;</button>
</div>

@code {
    private async Task Next()
    {
        var progress = new WizardProgress
        {
            CompletedSteps = [.. (ProgressSource as CascadingValueSource<WizardProgress>)
                is not null ? GetCurrentCompleted() : [], 1]
        };
        await ProgressSource.NotifyChangedAsync(progress);
        Nav.NavigateTo("/apply/experience");
    }

    private HashSet<int> GetCurrentCompleted()
    {
        // Read from the cascading parameter rather than the source
        return Progress?.CompletedSteps ?? [];
    }

    [CascadingParameter]
    private WizardProgress? Progress { get; set; }
}

@page "/apply/experience"
@layout ApplyLayout
@rendermode InteractiveServer

@using sv_1afb3bbe08134c74bbd9795a60098259.Models
@using sv_1afb3bbe08134c74bbd9795a60098259.Services

@inject ApplicationState AppState
@inject CascadingValueSource<WizardProgress> ProgressSource
@inject NavigationManager Nav

<PageTitle>Apply – Experience</PageTitle>

<h1>Step 2: Work Experience</h1>

@for (var i = 0; i < AppState.Experience.Count; i++)
{
    var index = i;
    <div class="card mb-3" style="max-width: 600px;">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h6 class="card-title mb-0">Position @(index + 1)</h6>
                @if (AppState.Experience.Count > 1)
                {
                    <button class="btn btn-sm btn-outline-danger"
                            @onclick="() => AppState.Experience.RemoveAt(index)">Remove</button>
                }
            </div>
            <div class="mb-2">
                <label class="form-label">Company</label>
                <input class="form-control" @bind="AppState.Experience[index].Company" />
            </div>
            <div class="mb-2">
                <label class="form-label">Job Title</label>
                <input class="form-control" @bind="AppState.Experience[index].Title" />
            </div>
            <div class="mb-2">
                <label class="form-label">Duration</label>
                <input class="form-control" @bind="AppState.Experience[index].Duration"
                       placeholder="e.g., Jan 2020 – Mar 2023" />
            </div>
        </div>
    </div>
}

<button class="btn btn-outline-secondary mb-4"
        @onclick="() => AppState.Experience.Add(new JobHistoryEntry())">
    + Add another position
</button>

<div class="d-flex gap-2 mt-2">
    <button class="btn btn-outline-secondary" @onclick="Back">&larr; Back</button>
    <button class="btn btn-primary" @onclick="Next">Next &rarr;</button>
</div>

@code {
    [CascadingParameter]
    private WizardProgress? Progress { get; set; }

    private async Task Next()
    {
        var completed = new HashSet<int>(Progress?.CompletedSteps ?? []) { 2 };
        await ProgressSource.NotifyChangedAsync(new WizardProgress { CompletedSteps = completed });
        Nav.NavigateTo("/apply/references");
    }

    private void Back() => Nav.NavigateTo("/apply/personal-info");
}

@page "/apply/references"
@layout ApplyLayout
@rendermode InteractiveServer

@using sv_1afb3bbe08134c74bbd9795a60098259.Models
