@using sv_1afb3bbe08134c74bbd9795a60098259.Models
@using sv_1afb3bbe08134c74bbd9795a60098259.Services

@inject ApplicationState AppState
@inject CascadingValueSource<WizardProgress> ProgressSource
@inject NavigationManager Nav

<PageTitle>Apply – Personal Info</PageTitle>

<h1>Step 1: Personal Information</h1>

<div class="mb-3" style="max-width: 500px;">
    <label class="form-label">Full Name</label>
    <input class="form-control" @bind="AppState.PersonalInfo.Name" />
</div>

<div class="mb-3" style="max-width: 500px;">
    <label class="form-label">Email Address</label>
    <input type="email" class="form-control" @bind="AppState.PersonalInfo.Email" />
</div>

<div class="d-flex gap-2 mt-4">
    <button class="btn btn-primary" @onclick="Next">Next &rarr;</button>
</div>

@code {
    private async Task Next()
    {
        var progress = new WizardProgress
        {
            CompletedSteps = [.. (ProgressSource as CascadingValueSource<WizardProgress>)
                is not null ? GetCurrentCompleted() : [], 1]
        };
        await ProgressSource.NotifyChangedAsync(progress);
        Nav.NavigateTo("/apply/experience");
    }

    private HashSet<int> GetCurrentCompleted()
