@page "/apply/review"
@layout ApplyLayout
@rendermode InteractiveServer

@using sv_1afb3bbe08134c74bbd9795a60098259.Models
@using sv_1afb3bbe08134c74bbd9795a60098259.Services

@inject ApplicationState AppState
@inject CascadingValueSource<WizardProgress> ProgressSource
@inject NavigationManager Nav

<PageTitle>Apply – Review</PageTitle>

<h1>Step 4: Review Your Application</h1>

<div style="max-width: 700px;">
    <div class="card mb-4">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Personal Information</strong>
            <a href="/apply/personal-info" class="btn btn-sm btn-outline-primary">Edit</a>
        </div>
        <div class="card-body">
            <dl class="row mb-0">
                <dt class="col-sm-3">Name</dt>
                <dd class="col-sm-9">@(string.IsNullOrWhiteSpace(AppState.PersonalInfo.Name) ? "—" : AppState.PersonalInfo.Name)</dd>
                <dt class="col-sm-3">Email</dt>
                <dd class="col-sm-9">@(string.IsNullOrWhiteSpace(AppState.PersonalInfo.Email) ? "—" : AppState.PersonalInfo.Email)</dd>
            </dl>
        </div>
    </div>

    <div class="card mb-4">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Work Experience</strong>
            <a href="/apply/experience" class="btn btn-sm btn-outline-primary">Edit</a>
        </div>
        <div class="card-body">
            @if (AppState.Experience.Any(e => !string.IsNullOrWhiteSpace(e.Company)))
            {
                @foreach (var job in AppState.Experience.Where(e => !string.IsNullOrWhiteSpace(e.Company)))
                {
                    <div class="mb-3">
                        <strong>@job.Title</strong> at @job.Company
                        <br />
                        <small class="text-muted">@job.Duration</small>
                    </div>
                }
            }
            else
            {
                <p class="text-muted mb-0">No experience entries added.</p>
            }
        </div>
    </div>

    <div class="card mb-4">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>References</strong>
            <a href="/apply/references" class="btn btn-sm btn-outline-primary">Edit</a>
        </div>
        <div class="card-body">
            @if (AppState.References.Any(r => !string.IsNullOrWhiteSpace(r.Name)))
            {
                @foreach (var reference in AppState.References.Where(r => !string.IsNullOrWhiteSpace(r.Name)))
                {
                    <div class="mb-3">
                        <strong>@reference.Name</strong> — @reference.Relationship
                        <br />
                        <small class="text-muted">@reference.Email</small>
                    </div>
                }
            }
            else
            {
                <p class="text-muted mb-0">No references added.</p>
            }
        </div>
    </div>
</div>

<div class="d-flex gap-2 mt-2">
    <button class="btn btn-outline-secondary" @onclick="Back">&larr; Back</button>
    <button class="btn btn-success" @onclick="Submit">Submit Application</button>
</div>

@if (submitted)
{
    <div class="alert alert-success mt-4" style="max-width: 700px;">
        Your application has been submitted successfully!
    </div>
}

@code {
    private bool submitted;

    [CascadingParameter]
    private WizardProgress? Progress { get; set; }

    private async Task Submit()
    {
        var completed = new HashSet<int>(Progress?.CompletedSteps ?? []) { 4 };
        await ProgressSource.NotifyChangedAsync(new WizardProgress { CompletedSteps = completed });
        submitted = true;
    }

    private void Back() => Nav.NavigateTo("/apply/references");
}

